(() => {
const $ = (s,r=document)=>r.querySelector(s); const $$=(s,r=document)=>[...r.querySelectorAll(s)];
const clone=o=>JSON.parse(JSON.stringify(o));
const STORAGE='auditoria365-v8-7';
let db=load(); let state={view:'dashboard',auditId:db.audits[0]?.id||null,clientId:db.audits[0]?.clientId||null,controlId:'A.5.15',tab:'resumen',query:'',modal:null,modalParent:null};
function load(){let x;try{x=JSON.parse(localStorage.getItem(STORAGE))||clone(window.AUDITHUB_SEED)}catch{x=clone(window.AUDITHUB_SEED)};['risks','policies','incidents','suppliers','history'].forEach(k=>x[k]||(x[k]=clone(window.AUDITHUB_SEED[k]||[])));(x.risks||[]).forEach(v=>v.comments||(v.comments=[]));(x.incidents||[]).forEach(v=>v.comments||(v.comments=[]));return x}
function save(){localStorage.setItem(STORAGE,JSON.stringify(db))}
const fw=()=>db.frameworks.find(x=>x.id===audit().frameworkId); const audit=()=>db.audits.find(x=>x.id===state.auditId)||db.audits[0]; const client=()=>db.clients.find(x=>x.id===audit().clientId)||db.clients[0];
const controls=()=>fw()?.sections.flatMap(s=>s.controls.map(c=>({id:c[0],title:c[1],section:s.title,minCategory:c[2]||''})))||[];
const ctl=(id=state.controlId)=>controls().find(c=>c.id===id);
const slug=s=>(s||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/\s+/g,'-');
const esc=s=>String(s??'').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]));

function parseTime(v){if(!v)return 0;let s=String(v).trim();let d=new Date(s);if(!isNaN(d))return d.getTime();let m=s.match(/(\d{1,2})\/(\d{1,2})\/(\d{4})(?:,\s*(\d{1,2}):(\d{2})(?::(\d{2}))?)?/);if(m){let[,dd,mm,yy,hh='0',mi='0',ss='0']=m;return new Date(+yy,+mm-1,+dd,+hh,+mi,+ss).getTime()}m=s.match(/(\d{4})-(\d{2})-(\d{2})/);if(m){let[,yy,mm,dd]=m;return new Date(+yy,+mm-1,+dd).getTime()}return 0}
function controlHistoryItems(c){let a=audit(), items=[];let direct=db.history.filter(x=>x.auditId===a.id&&x.controlId===c.id).map(x=>({action:x.action,date:x.date,user:x.user,state:x.state,sort:parseTime(x.date)}));items.push(...direct);db.documents.filter(d=>d.auditId===a.id&&d.controlId===c.id).forEach(d=>items.push({action:'Evidencia registrada: '+d.name,date:d.added,user:d.owner||'Propietario del documento',state:d.status,sort:parseTime(d.added)}));db.findings.filter(f=>f.auditId===a.id&&f.controlId===c.id).forEach(f=>items.push({action:'Hallazgo vinculado: '+f.title,date:f.due||a.end,user:f.owner||'Auditor',state:f.status,sort:parseTime(f.due||a.end)}));db.actions.filter(x=>x.auditId===a.id&&x.controlId===c.id).forEach(x=>items.push({action:'Acción de seguimiento: '+x.title,date:x.due||a.end,user:x.owner||'Responsable',state:x.status,sort:parseTime(x.due||a.end)}));let current=a.controlStates[c.id];if(current||a.notes[c.id])items.push({action:'Estado actual del control documentado',date:a.end||'2026-10-31',user:db.settings.auditor,state:current||'pendiente',sort:parseTime(a.end||'2026-10-31')});let seen=new Set();return items.filter(x=>{let k=[x.action,x.date,x.user,x.state].join('|');if(seen.has(k))return false;seen.add(k);return true}).sort((b,a)=>a.sort-b.sort)}
function reportLibrary(){let items=db.documents.filter(d=>d.auditId===state.auditId&&d.type==='PDF'&&(/informe/i.test(d.name)||/\/informes\//i.test(d.path||'')));return `<div class="card" style="margin-bottom:16px"><div class="section-title"><div><h3>Biblioteca de informes</h3><p class="muted">Informes exclusivos de ${esc(client().name)} y la auditoría ${esc(audit().code)}.</p></div><span class="badge">${items.length} informes</span></div><div class="grid three compact-cards">${items.map(d=>`<div class="card"><div class="section-title"><span class="badge">${esc(d.controlId)}</span>${status(d.status)}</div><h3>${esc(d.name.replace(/_/g,' ').replace(/\.pdf$/i,''))}</h3><p class="muted">${esc(d.comment||'')}</p><div class="actions"><button class="btn primary" data-doc="${d.id}">Abrir informe</button></div></div>`).join('')||'<div class="empty">Sin informes para esta auditoría.</div>'}</div></div>`}
function pct(){let cs=controls(),map=audit().controlStates||{},score=cs.reduce((n,c)=>n+({cumple:1,parcial:.5,'no-cumple':0,pendiente:0}[map[c.id]||'pendiente']),0);return cs.length?Math.round(score/cs.length*100):0}
function auditPct(a){let f=db.frameworks.find(x=>x.id===a.frameworkId),cs=f?.sections.flatMap(s=>s.controls.map(c=>c[0]))||[],map=a.controlStates||{},score=cs.reduce((n,id)=>n+({cumple:1,parcial:.5,'no-cumple':0,pendiente:0}[map[id]||'pendiente']),0);return cs.length?Math.round(score/cs.length*100):0}
function ensBadge(a=audit()){return a.frameworkId==='ens-2022'?`<span class="ens-category ${slug(a.ensCategory||'BÁSICA')}">ENS ${esc(a.ensCategory||'BÁSICA')}</span>`:''}
function frameworkMark(a=audit()){if(a.frameworkId==='ens-2022'){let cat=(a.ensCategory||'BÁSICA').toUpperCase();return `<div class="framework-mark ens ${slug(cat)}" title="Auditoría ENS 2022 · Categoría ${esc(cat)}"><span class="framework-symbol">ENS</span><span><b>ENS 2022</b><small>Categoría ${esc(cat)}</small></span></div>`}return `<div class="framework-mark iso" title="Auditoría basada en ISO/IEC 27001:2022"><span class="framework-symbol">27K</span><span><b>ISO/IEC 27001</b><small>Edición 2022</small></span></div>`}
function frameworkSummary(){return fw().sections.map(s=>{let ids=s.controls.map(c=>c[0]),ok=ids.filter(id=>(audit().controlStates[id]||'')==='cumple').length,part=ids.filter(id=>(audit().controlStates[id]||'')==='parcial').length;return {name:s.title,total:ids.length,ok,part,pct:ids.length?Math.round((ok+part*.5)/ids.length*100):0}})}
function icon(n){return ({dashboard:'⌂',clients:'◫',audits:'▣',frameworks:'⌘',documents:'▤',risks:'◆',policies:'▧',incidents:'!',suppliers:'♢',findings:'⚑',actions:'✓',reports:'▥',settings:'⚙'}[n]||'•')}
function shell(content){return `<div class="app-shell"><aside class="sidebar" id="sidebar"><div class="brand"><div class="brand-mark">◇</div><div>Auditoria365<small>Auditorías & Compliance</small></div></div><nav class="nav">${[['dashboard','Dashboard'],['clients','Clientes'],['audits','Auditorías'],['frameworks','Marcos de trabajo'],['documents','Documentos'],['risks','Riesgos'],['policies','Políticas'],['incidents','Incidentes'],['suppliers','Proveedores'],['findings','Hallazgos'],['actions','Acciones'],['reports','Informes'],['settings','Configuración']].map(x=>`<button data-nav="${x[0]}" class="${state.view===x[0]||state.view==='audit'&&x[0]==='audits'||state.view==='control'&&x[0]==='audits'?'active':''}"><span>${icon(x[0])}</span>${x[1]}</button>`).join('')}</nav><div class="side-footer"><div class="user-chip"><div class="avatar">MC</div><div><b>${esc(db.settings.auditor)}</b><div class="muted" style="font-size:11px">Auditor</div></div></div></div></aside><main class="main"><header class="topbar"><div><button class="btn mobile-menu" id="menuBtn">☰</button></div><div class="audit-context">${frameworkMark()}<div class="audit-client-text"><b>${esc(client().code)} · ${esc(client().name)}</b><small>${esc(audit().code)} · ${esc(fw().short||fw().name)}</small></div><select id="auditSwitcher">${db.audits.map(a=>`<option value="${a.id}" ${a.id===state.auditId?'selected':''}>${esc(a.code)} · ${esc(a.name)}</option>`).join('')}</select></div><div class="search">⌕<input id="globalSearch" placeholder="Buscar en ${esc(audit().code)}..." value="${esc(state.query)}"></div><div>◌ &nbsp; ?</div></header><section class="content"><div class="demo-banner">DATOS DE DEMOSTRACIÓN · ORGANIZACIÓN FICTICIA · No contiene información real</div>${content}</section><footer class="app-footer"><b>© 2026 Auditoria365</b><span>Auditorías & Compliance</span><span>Todos los derechos reservados - OpenTrust Group</span></footer></main></div>${state.modal?modal():''}`}
function render(){let html=views[state.view]?views[state.view]():views.dashboard();$('#app').innerHTML=shell(html);bind()}
function status(s){return `<span class="status ${slug(s)}">${esc(s?.replace('-', ' ')||'Pendiente')}</span>`}
function docTable(docs){return docs.length?`<div class="table-wrap"><table class="table"><thead><tr><th>Documento</th><th>Control</th><th>Fecha</th><th>Estado</th><th>Propietario</th><th>Carpeta</th><th></th></tr></thead><tbody>${docs.map(d=>`<tr><td><div style="display:flex;align-items:center;gap:10px"><div class="file-icon">${esc(d.type)}</div><div><b>${esc(d.name)}</b><div class="muted">${formatSize(d.size)}</div></div></div></td><td><span class="badge">${esc(d.controlId)}</span></td><td>${esc(d.added)}</td><td>${status(d.status)}</td><td>${esc(d.owner||'')}</td><td><code class="folder-code">${esc(d.folderPath||'IndexedDB / '+(audit()?.code||''))}</code></td><td><button class="btn" data-doc="${d.id}">Vista previa</button></td></tr>`).join('')}</tbody></table></div>`:'<div class="empty">Todavía no hay documentos asociados.</div>'}
function infrastructureGallery(compact=false){let docs=db.documents.filter(d=>d.auditId===state.auditId&&['SVG','PNG','JPG','JPEG','WEBP'].includes((d.type||'').toUpperCase()));return docs.length?`<div class="infra-gallery ${compact?'compact':''}">${docs.map(d=>{let src=d.previewImage||d.path;return `<button class="infra-tile" data-doc="${d.id}"><img src="${src}" alt="${esc(d.name)}" loading="lazy" onerror="this.closest('.infra-tile').classList.add('image-error');this.style.display='none'"><span class="image-fallback">Vista previa gráfica no disponible</span><span><b>${esc(d.name.replace(/_/g,' ').replace(/\.(svg|png|jpe?g|webp)$/i,''))}</b><small>${esc(d.controlId)} · ${esc(d.owner)}</small></span></button>`}).join('')}</div>`:'<div class="empty">Esta auditoría todavía no tiene diagramas asociados.</div>'}
function dashboard(){let a=audit(),docs=db.documents.filter(d=>d.auditId===a.id),find=db.findings.filter(f=>f.auditId===a.id),act=db.actions.filter(x=>x.auditId===a.id);return `<div class="page-head"><div><h1>Dashboard de auditoría</h1><p class="muted">Vista general de cumplimiento, evidencias y acciones.</p></div><div class="actions"><button class="btn" data-nav="reports">Generar informe</button><button class="btn primary" data-open="newAudit">+ Nueva auditoría</button></div></div><div class="grid stats"><div class="card stat"><div class="muted">Cumplimiento global</div><div class="value">${pct()}%</div><div class="progress"><span style="width:${pct()}%"></span></div></div><div class="card stat"><div class="muted">Evidencias</div><div class="value">${docs.length}</div><div class="trend good">${docs.filter(d=>d.status==='Validado').length} validadas</div></div><div class="card stat"><div class="muted">Hallazgos abiertos</div><div class="value">${find.filter(f=>f.status!=='Cerrado').length}</div><div class="trend bad">${find.filter(f=>f.severity==='Alta').length} de severidad alta</div></div><div class="card stat"><div class="muted">Acciones en curso</div><div class="value">${act.filter(x=>x.status!=='Completada').length}</div><div class="trend warn">${act.filter(x=>new Date(x.due)<new Date()&&x.status!=='Completada').length} vencidas</div></div></div><div class="grid two" style="margin-top:16px"><div class="card"><div class="section-title"><h2>${esc(a.name)}</h2><div>${ensBadge(a)} ${status(a.status)}</div></div><div class="meta-list"><b>Organización</b><span>${esc(a.organization)}</span><b>Marco</b><span>${esc(fw().name)}</span><b>Alcance</b><span>${esc(a.scope)}</span><b>Periodo</b><span>${a.start} → ${a.end}</span>${a.frameworkId==='ens-2022'?`<b>Categoría ENS</b><span>${esc(a.ensCategory)} · ${Object.entries(a.ensDimensions||{}).map(([k,v])=>k+': '+v).join(' · ')}</span>`:''}</div><div style="margin-top:18px"><button class="btn primary" data-open-audit="${a.id}">Abrir auditoría</button></div></div><div class="card"><div class="section-title"><h3>Estado de controles</h3></div><div class="donut kpi-ring"><div class="donut-value">${pct()}%</div></div><div class="mini-list" style="margin-top:16px">${['cumple','parcial','no-cumple','pendiente'].map(s=>`<div class="mini-item"><span>${status(s)}</span><b>${controls().filter(c=>(a.controlStates[c.id]||'pendiente')===s).length}</b></div>`).join('')}</div></div></div><div class="grid two" style="margin-top:16px"><div class="card"><div class="section-title"><h3>Últimos documentos</h3><button class="btn" data-nav="documents">Ver todos</button></div>${docTable(docs.slice(-5).reverse())}</div><div class="card"><div class="section-title"><h3>Acciones prioritarias</h3><button class="btn" data-nav="actions">Ver todas</button></div>${act.length?`<div class="mini-list">${act.slice(0,5).map(x=>`<div class="mini-item"><div><b>${esc(x.title)}</b><div class="muted">${esc(x.owner)} · ${x.due}</div></div>${status(x.status)}</div>`).join('')}</div>`:'<div class="empty">Sin acciones</div>'}</div></div><div class="card" style="margin-top:16px"><div class="section-title"><div><h3>Infraestructura y seguridad</h3><p class="muted">Diagramas de servidores, red, firewalls, segmentación y controles por capa.</p></div><button class="btn" data-nav="documents">Ver biblioteca</button></div>${infrastructureGallery(true)}</div><div class="grid four module-grid" style="margin-top:16px"><button class="module-card" data-nav="risks"><span>◆</span><div><b>Registro de riesgos</b><small>${db.risks.filter(r=>r.auditId===a.id).length} riesgos identificados</small></div></button><button class="module-card" data-nav="policies"><span>▧</span><div><b>Gestión de políticas</b><small>${db.policies.filter(r=>r.auditId===a.id).length} políticas controladas</small></div></button><button class="module-card" data-nav="incidents"><span>!</span><div><b>Incidentes</b><small>${db.incidents.filter(r=>r.auditId===a.id&&r.status!=="Cerrado").length} abiertos</small></div></button><button class="module-card" data-nav="suppliers"><span>♢</span><div><b>Terceros</b><small>${db.suppliers.filter(r=>r.auditId===a.id).length} proveedores evaluados</small></div></button></div>`}
function clients(){return `<div class="page-head"><div><h1>Clientes</h1><p class="muted">Clientes, códigos y auditorías asociadas.</p></div><button class="btn primary" data-open="newClient">+ Nuevo cliente</button></div><div class="grid three">${db.clients.map(c=>{let aa=db.audits.filter(a=>a.clientId===c.id);return `<div class="card client-card"><div class="section-title"><span class="badge">${esc(c.code)}</span>${status(c.status)}</div><h3>${esc(c.name)}</h3><p class="muted">${esc(c.sector)} · ${esc(c.country)}</p><div class="meta-list"><b>Contacto</b><span>${esc(c.contact)}</span><b>Auditorías</b><span>${aa.length}</span><b>CIF demo</b><span>${esc(c.taxId)}</span></div><div class="mini-list">${aa.map(a=>`<button class="mini-item client-audit" data-open-audit="${a.id}"><div><b>${esc(a.code)}</b><div class="muted">${esc(a.name)}</div></div>${status(a.status)}</button>`).join('')}</div></div>`}).join('')}</div>`}
function audits(){return `<div class="page-head"><div><h1>Auditorías</h1><p class="muted">Gestiona auditorías, alcance, responsables y progreso.</p></div><button class="btn primary" data-open="newAudit">+ Nueva auditoría</button></div><div class="grid three">${db.audits.map(a=>{let ap=auditPct(a);return `<div class="card"><div class="section-title"><div><span class="badge">${esc(db.frameworks.find(f=>f.id===a.frameworkId)?.short)}</span> ${ensBadge(a)}</div>${status(a.status)}</div><div class="audit-code">${esc(a.code||a.id)}</div><h3>${esc(a.name)}</h3><p class="muted">${esc(db.clients.find(c=>c.id===a.clientId)?.code||'')} · ${esc(a.organization)}</p><p>${esc(a.scope)}</p>${a.frameworkId==='ens-2022'?`<div class="ens-dimensions">${Object.entries(a.ensDimensions||{}).map(([k,v])=>`<span><b>${k}</b>${v}</span>`).join('')}</div>`:''}<div class="progress"><span style="width:${ap}%"></span></div><div style="display:flex;justify-content:space-between;margin:8px 0 16px"><span class="muted">Progreso</span><b>${ap}%</b></div><button class="btn primary" data-open-audit="${a.id}">Abrir auditoría</button></div>`}).join('')}</div>`}
function auditView(){let a=audit();return `<div class="page-head"><div><div class="muted">Auditorías / ${esc(fw().name)}</div><h1>${esc(a.name)}</h1></div><div class="actions"><button class="btn" data-nav="reports">Exportar informe</button><button class="btn primary" data-upload="${state.controlId}">+ Añadir documento</button></div></div><div class="tabs"><button class="active">Estructura</button><button data-nav="documents">Documentos</button><button data-nav="risks">Riesgos</button><button data-nav="policies">Políticas</button><button data-nav="findings">Hallazgos</button><button data-nav="actions">Acciones</button><button data-nav="reports">Informes</button></div><div class="audit-layout"><div class="card tree">${tree()}</div><div class="card">${controlPanel()}</div></div>`}
function tree(){let a=audit();return fw().sections.map(s=>`<div class="tree-section"><button>${esc(s.title)}</button><div class="tree-controls">${s.controls.map(c=>`<button class="${state.controlId===c[0]?'active':''}" data-control="${c[0]}"><span><span class="dot ${a.controlStates[c[0]]||'pendiente'}"></span>${esc(c[0])} ${esc(c[1])}${c[2]?`<small class="measure-category">${esc(c[2])}</small>`:''}</span><span>${db.documents.filter(d=>d.auditId===a.id&&d.controlId===c[0]).length||''}</span></button>`).join('')}</div></div>`).join('')}
function controlPanel(){let c=ctl(),a=audit(),docs=db.documents.filter(d=>d.auditId===a.id&&d.controlId===c.id),st=a.controlStates[c.id]||'pendiente';return `<div class="control-head"><div><div class="control-id">${esc(c.id)} · ${esc(c.section)} ${c.minCategory?`· Perfil demo ${esc(c.minCategory)}`:''}</div><div class="control-title">${esc(c.title)}</div><p class="muted">Validación manual del requisito y gestión de evidencias relacionadas.</p></div>${status(st)}</div><div class="tabs"><button class="${state.tab==='resumen'?'active':''}" data-tab="resumen">Resumen</button><button class="${state.tab==='evidencias'?'active':''}" data-tab="evidencias">Evidencias (${docs.length})</button><button class="${state.tab==='validacion'?'active':''}" data-tab="validacion">Validación</button><button class="${state.tab==='historial'?'active':''}" data-tab="historial">Historial</button></div>${state.tab==='resumen'?`<div class="grid two"><div><div class="card" style="box-shadow:none"><h3>Estado del control</h3><div class="meta-list"><b>Estado</b><span>${status(st)}</span><b>Evidencias</b><span>${docs.length}</span><b>Hallazgos</b><span>${db.findings.filter(f=>f.auditId===a.id&&f.controlId===c.id).length}</span></div><p><b>Observaciones</b></p><p class="muted">${esc(a.notes[c.id]||'Todavía no se han añadido observaciones para este control.')}</p></div></div><div class="card" style="box-shadow:none"><h3>Acciones rápidas</h3><div class="actions"><button class="btn primary" data-upload="${c.id}">Añadir evidencia</button><button class="btn" data-tab="validacion">Validar control</button><button class="btn" data-open="newFinding">Crear hallazgo</button></div></div></div>`:state.tab==='evidencias'?`<div class="dropzone" data-upload="${c.id}"><b>Arrastra o selecciona documentos</b><div>PDF, DOCX, XLSX, imágenes, TXT y CSV</div></div><div style="margin-top:14px">${docTable(docs)}</div>`:state.tab==='validacion'?validationForm(c,st):historyPanel(c)}`}
function historyPanel(c){let h=controlHistoryItems(c);return h.length?`<div class="card" style="box-shadow:none;border:1px dashed var(--line);margin-bottom:14px"><b>Traza del auditor</b><div class="muted" style="margin-top:6px">El historial es inmutable dentro de la demo y se muestra como registro de trazabilidad del control.</div></div><div class="timeline">${h.map(x=>`<div class="timeline-item"><span></span><div><b>${esc(x.action)}</b><div class="muted">${esc(x.date)} · ${esc(x.user)} · ${esc(x.state||'')}</div></div></div>`).join('')}</div>`:'<div class="empty">Todavía no hay actividad registrada para este control.</div>'}
function validationForm(c,st){return `<div class="form-grid"><div class="field"><label>Estado del control</label><select id="controlState"><option value="pendiente" ${st==='pendiente'?'selected':''}>Pendiente</option><option value="cumple" ${st==='cumple'?'selected':''}>Cumple</option><option value="parcial" ${st==='parcial'?'selected':''}>Cumple parcialmente</option><option value="no-cumple" ${st==='no-cumple'?'selected':''}>No cumple</option></select></div><div class="field"><label>Responsable de validación</label><input value="${esc(db.settings.auditor)}" disabled></div><div class="field" style="grid-column:1/-1"><label>Observaciones del auditor</label><textarea id="controlNotes">${esc(audit().notes[c.id]||'')}</textarea></div></div><div class="actions" style="margin-top:14px"><button class="btn primary" id="saveValidation">Guardar evaluación</button></div>`}
function documents(){let docs=db.documents.filter(d=>!state.auditId||d.auditId===state.auditId);return `<div class="page-head"><div><h1>Documentos y evidencias</h1><p class="muted">Biblioteca documental exclusiva de ${esc(client().name)} · ${esc(audit().code)}.</p></div><button class="btn primary" data-upload="${state.controlId}">+ Añadir documento</button></div><div class="card"><div class="section-title"><div><h3>Diagramas de infraestructura y seguridad</h3><p class="muted">Documentación gráfica propia de la auditoría activa. No se comparten evidencias entre clientes.</p></div></div>${infrastructureGallery()}</div><div class="card" style="margin-top:16px"><div class="section-title"><h3>${docs.length} documentos</h3><span class="muted">Incluye evidencias reales de demostración y archivos añadidos por el auditor</span></div>${docTable(docs)}</div>`}
function riskZone(score){return score>=20?'critical':score>=15?'very-high':score>=10?'high':score>=5?'medium':'low'}

function riskMatrix(rows,large=false){
  let cells=[];
  for(let p=5;p>=1;p--){
    for(let i=1;i<=5;i++){
      let items=rows.filter(r=>r.likelihood===p&&r.impact===i),score=p*i;
      cells.push(`<button class="risk-cell ${riskZone(score)}" title="Probabilidad ${p} · Impacto ${i} · Nivel ${score}" ${items.length?'data-risk-detail="'+items[0].id+'"':''}><span class="risk-score">${score}</span><div class="risk-dots">${items.map(r=>`<span title="${esc(r.id+' · '+r.title)}">${esc(r.id.toUpperCase())}</span>`).join('')}</div></button>`)
    }
  }
  return `<section class="card risk-matrix-card ${large?'is-large':''}"><div class="section-title"><div><h2>Matriz de riesgos 5×5</h2><p class="muted">Impacto horizontal · Probabilidad vertical · Pulsa un riesgo para abrir su detalle</p></div><div class="actions"><span class="badge">${rows.length} riesgos demo</span>${large?'':`<button class="btn compact matrix-zoom" data-open-matrix title="Ampliar matriz">🔍 Ver grande</button>`}</div></div><div class="risk-matrix-wrap"><div class="risk-y-title">Probabilidad</div><div class="risk-matrix-grid"><div class="matrix-corner"></div>${[1,2,3,4,5].map(i=>`<div class="matrix-axis top">${i}<small>${['Insignificante','Menor','Moderado','Mayor','Crítico'][i-1]}</small></div>`).join('')}${[5,4,3,2,1].map((p,ri)=>`<div class="matrix-axis side">${p}<small>${['Raro','Improbable','Posible','Probable','Casi seguro'][p-1]}</small></div>${cells.slice(ri*5,ri*5+5).join('')}`).join('')}</div><div class="risk-x-title">Impacto</div></div><div class="risk-legend"><span class="low">1-4 Bajo</span><span class="medium">5-9 Moderado</span><span class="high">10-14 Alto</span><span class="very-high">15-19 Muy alto</span><span class="critical">20-25 Crítico</span></div></section>`
}

function risks(){let rows=db.risks.filter(r=>r.auditId===state.auditId),score=r=>r.likelihood*r.impact;return `<div class="page-head"><div><h1>Registro de riesgos</h1><p class="muted">Identificación, valoración inherente, tratamiento, riesgo residual y seguimiento.</p></div><button class="btn primary" data-open="newRisk">+ Nuevo riesgo</button></div><div class="grid stats"><div class="card stat"><div class="muted">Riesgos registrados</div><div class="value">${rows.length}</div></div><div class="card stat"><div class="muted">Muy altos / críticos</div><div class="value">${rows.filter(r=>score(r)>=15).length}</div></div><div class="card stat"><div class="muted">En tratamiento</div><div class="value">${rows.filter(r=>r.status==='En tratamiento').length}</div></div><div class="card stat"><div class="muted">Residual medio</div><div class="value">${rows.length?Math.round(rows.reduce((n,r)=>n+(r.residual||score(r)),0)/rows.length):0}</div></div></div>${riskMatrix(rows)}<div class="card" style="margin-top:16px"><div class="section-title"><div><h2>Detalle del registro</h2><p class="muted">Todos los valores y escenarios corresponden a datos ficticios de demostración.</p></div><button class="btn" data-doc="d8">Abrir registro XLSX</button></div>${rows.length?`<div class="table-wrap"><table class="table"><thead><tr><th>ID</th><th>Riesgo</th><th>Activo / proceso</th><th>Prob.</th><th>Impacto</th><th>Inherente</th><th>Residual</th><th>Tratamiento</th><th>Responsable</th><th>Estado</th><th></th></tr></thead><tbody>${rows.map(r=>`<tr><td><span class="badge">${esc(r.id.toUpperCase())}</span></td><td><b>${esc(r.title)}</b><div class="muted">${esc(r.description)}</div></td><td>${esc(r.asset)}</td><td>${r.likelihood}/5</td><td>${r.impact}/5</td><td><span class="risk-level l${score(r)>=15?'high':score(r)>=8?'medium':'low'}">${score(r)}</span></td><td><b>${r.residual||'-'}</b></td><td>${esc(r.treatment)}</td><td>${esc(r.owner)}</td><td>${status(r.status)}</td><td><button class="btn compact" data-risk-detail="${r.id}">Ver detalle</button></td></tr>`).join('')}</tbody></table></div>`:'<div class="empty">No hay riesgos registrados.</div>'}</div>`}function policies(){let rows=db.policies.filter(r=>r.auditId===state.auditId);return `<div class="page-head"><div><h1>Gestión de políticas</h1><p class="muted">Ciclo de vida, aprobación, revisión y relación con controles.</p></div><button class="btn primary" data-open="newPolicy">+ Nueva política</button></div><div class="grid three compact-cards">${rows.map(p=>`<div class="card policy-card"><div class="section-title">${status(p.status)}<span class="badge">v${esc(p.version)}</span></div><h3>${esc(p.name)}</h3><p class="muted">${esc(p.owner)}</p><div class="meta-list"><b>Aprobada</b><span>${esc(p.approved||'Pendiente')}</span><b>Próxima revisión</b><span>${esc(p.review)}</span><b>Controles</b><span>${esc(p.controls.join(', '))}</span></div><div class="progress"><span style="width:${p.status==='Aprobada'?100:p.status==='En revisión'?65:25}%"></span></div><div class="card-actions"><button class="btn compact" data-policy-detail="${p.id}">Ver detalle</button></div></div>`).join('')||'<div class="card empty">No hay políticas registradas.</div>'}</div>`}
function incidents(){let rows=db.incidents.filter(r=>r.auditId===state.auditId);return `<div class="page-head"><div><h1>Gestión de incidentes</h1><p class="muted">Registro, clasificación, respuesta, evidencias y lecciones aprendidas.</p></div><button class="btn primary" data-open="newIncident">+ Nuevo incidente</button></div><div class="card">${rows.length?`<div class="table-wrap"><table class="table"><thead><tr><th>Incidente</th><th>Fecha</th><th>Severidad</th><th>Responsable</th><th>Control</th><th>Estado</th><th></th></tr></thead><tbody>${rows.map(i=>`<tr><td><b>${esc(i.title)}</b><div class="muted">${esc(i.description)}</div></td><td>${esc(i.date)}</td><td>${status(i.severity)}</td><td>${esc(i.owner)}</td><td><span class="badge">${esc(i.controlId)}</span></td><td>${status(i.status)}</td><td><button class="btn compact" data-incident-detail="${i.id}">Ver detalle</button></td></tr>`).join('')}</tbody></table></div>`:'<div class="empty">No hay incidentes registrados.</div>'}</div>`}
function suppliers(){let rows=db.suppliers.filter(r=>r.auditId===state.auditId);return `<div class="page-head"><div><h1>Riesgo de proveedores</h1><p class="muted">Inventario de terceros, criticidad, evaluación y vencimientos.</p></div><button class="btn primary" data-open="newSupplier">+ Nuevo proveedor</button></div><div class="grid three compact-cards">${rows.map(v=>`<div class="card supplier-card"><div class="section-title"><span class="badge">${esc(v.category)}</span>${status(v.status)}</div><h3>${esc(v.name)}</h3><p class="muted">${esc(v.service)}</p><div class="meta-list"><b>Criticidad</b><span>${status(v.criticality)}</span><b>Riesgo</b><span>${esc(v.risk)}/25</span><b>Próxima revisión</b><span>${esc(v.review)}</span><b>Responsable</b><span>${esc(v.owner)}</span></div><div class="progress"><span style="width:${Math.min(100,v.risk*4)}%"></span></div><div class="card-actions"><button class="btn compact" data-supplier-detail="${v.id}">Ver detalle</button></div></div>`).join('')||'<div class="card empty">No hay proveedores registrados.</div>'}</div>`}
function findings(){let rows=db.findings.filter(f=>f.auditId===state.auditId);return `<div class="page-head"><div><h1>Hallazgos</h1><p class="muted">No conformidades, observaciones y oportunidades de mejora.</p></div><button class="btn primary" data-open="newFinding">+ Nuevo hallazgo</button></div><div class="card">${rows.length?`<div class="table-wrap"><table class="table"><thead><tr><th>Hallazgo</th><th>Control</th><th>Severidad</th><th>Responsable</th><th>Fecha objetivo</th><th>Estado</th><th></th></tr></thead><tbody>${rows.map(f=>`<tr><td><b>${esc(f.title)}</b><div class="muted">${esc(f.description)}</div></td><td>${esc(f.controlId)}</td><td>${status(f.severity)}</td><td>${esc(f.owner)}</td><td>${esc(f.due)}</td><td>${status(f.status)}</td><td><button class="btn compact" data-finding-detail="${f.id}">Ver detalle</button></td></tr>`).join('')}</tbody></table></div>`:'<div class="empty">No hay hallazgos registrados.</div>'}</div>`}
function actionsView(){let rows=db.actions.filter(a=>a.auditId===state.auditId);return `<div class="page-head"><div><h1>Plan de acciones</h1><p class="muted">Seguimiento de medidas correctivas, responsables, evidencias y cierre.</p></div><button class="btn primary" data-open="newAction">+ Nueva acción</button></div><div class="grid three compact-cards">${rows.map(a=>`<div class="card action-card"><div class="section-title">${status(a.status)}<b>${a.progress}%</b></div><div class="action-tags"><span class="badge">${esc(a.controlId||'Sin control')}</span><span class="priority ${slug(a.priority||'Media')}">${esc(a.priority||'Media')}</span></div><h3>${esc(a.title)}</h3><p class="muted">Responsable: ${esc(a.owner)}</p><p>Fecha objetivo: <b>${esc(a.due)}</b></p><div class="progress"><span style="width:${a.progress}%"></span></div><button class="btn primary full" data-action-detail="${a.id}">Continuar acción</button></div>`).join('')}</div>`}
function reports(){let a=audit(),find=db.findings.filter(f=>f.auditId===a.id),ris=db.risks.filter(r=>r.auditId===a.id),incs=db.incidents.filter(i=>i.auditId===a.id),acts=db.actions.filter(x=>x.auditId===a.id),docs=db.documents.filter(d=>d.auditId===a.id),ctrls=controls();let summary=frameworkSummary(); let sev={crit:find.filter(x=>x.severity==='Crítica').length+incs.filter(x=>x.severity==='Crítica').length,alta:find.filter(x=>x.severity==='Alta').length+incs.filter(x=>x.severity==='Alta').length,media:find.filter(x=>x.severity==='Media').length+incs.filter(x=>x.severity==='Media').length,baja:find.filter(x=>x.severity==='Baja').length+incs.filter(x=>x.severity==='Baja').length}; let chartStep=560/Math.max(1,summary.length),barWidth=Math.min(54,chartStep-12),palette=['#275EFE','#7C3AED','#0F766E','#E65A3A','#B7791F','#17C0E9','#2563EB','#9333EA'];let bar=summary.map((s,i)=>{let x=45+i*chartStep+(chartStep-barWidth)/2,cx=x+barWidth/2;return `<g><rect x="${x}" y="${190-(s.pct*1.2)}" width="${barWidth}" height="${s.pct*1.2}" rx="8" fill="${palette[i%palette.length]}"/><text x="${cx}" y="${184-(s.pct*1.2)}" text-anchor="middle" font-size="10" font-weight="800" fill="#16304F">${s.pct}%</text><text x="${cx}" y="212" text-anchor="middle" font-size="8" fill="#52647C">${s.name.slice(0,12)}</text></g>`}).join(''); let sevBars=[['Crít.',sev.crit,'#DC2626'],['Altos',sev.alta,'#F97316'],['Medios',sev.media,'#FBBF24'],['Bajos',sev.baja,'#22C55E'],['Acciones',acts.length,'#275EFE']].map((s,i)=>`<g><rect x="${64+i*84}" y="${190-(Math.max(1,s[1])*18)}" width="48" height="${Math.max(1,s[1])*18}" rx="10" fill="${s[2]}"/><text x="${88+i*84}" y="${184-(Math.max(1,s[1])*18)}" text-anchor="middle" font-size="11" font-weight="800" fill="#16304F">${s[1]}</text><text x="${88+i*84}" y="212" text-anchor="middle" font-size="10" fill="#52647C">${s[0]}</text></g>`).join(''); return `<div class="page-head no-print"><div><h1>Informe de auditoría</h1><p class="muted">Versión ejecutiva preparada para imprimir o guardar como PDF.</p></div><div class="actions"><button class="btn" data-doc="${db.documents.find(d=>d.auditId===a.id&&/Informe_Ejecutivo/i.test(d.name))?.id||''}">Abrir informe ejecutivo</button><button class="btn primary" onclick="window.print()">Imprimir / PDF</button></div></div>${reportLibrary()}<div class="card report"><div class="print-only"><h1>Informe de auditoría</h1></div><div class="detail-hero"><div><div class="eyebrow">Informe ejecutivo</div><h2>${esc(a.name)}</h2><p>${esc(a.organization)} · ${esc(fw().name)} · Alcance: ${esc(a.scope)}. Periodo auditado: ${a.start} - ${a.end}. Todos los datos mostrados corresponden a una organización ficticia y se emplean únicamente con fines de demostración.</p></div><div>${status('Validado')}</div></div><div class="detail-grid"><b>Auditor responsable</b><span>${esc(a.lead)}</span><b>Organización</b><span>${esc(a.organization)}</span><b>Marco</b><span>${esc(fw().name)}</span>${a.frameworkId==='ens-2022'?`<b>Categoría ENS</b><span>${esc(a.ensCategory)} · ${Object.entries(a.ensDimensions||{}).map(([k,v])=>k+': '+v).join(' · ')}</span>`:''}<b>Evidencias revisadas</b><span>${docs.length}</span><b>Riesgos registrados</b><span>${ris.length}</span><b>Incidentes registrados</b><span>${incs.length}</span></div><h2>Resumen ejecutivo</h2><div class="report-kpis"><div class="report-kpi"><div class="muted">Cumplimiento global</div><div class="n">${pct()}%</div></div><div class="report-kpi"><div class="muted">Hallazgos abiertos</div><div class="n">${find.length}</div></div><div class="report-kpi"><div class="muted">Acciones activas</div><div class="n">${acts.length}</div></div><div class="report-kpi"><div class="muted">Incidentes</div><div class="n">${incs.length}</div></div></div><div class="report-grid" style="margin-top:16px"><div class="report-panel"><h3 style="margin-top:0">Cobertura por dominio</h3><svg class="report-svg" viewBox="0 0 640 240"><line x1="44" y1="190" x2="610" y2="190" stroke="#CBD5E1" stroke-width="2"/>${bar}</svg></div><div class="report-panel"><h3 style="margin-top:0">Prioridades y conclusión profesional</h3><ul class="report-bullets"><li>${a.frameworkId==='ens-2022'?'El sistema ENS presenta avances en política, análisis de riesgos, arquitectura, continuidad y monitorización.':'El SGSI presenta una base sólida en identidad, copias de seguridad, monitorización y respuesta a incidentes.'}</li><li>${a.frameworkId==='ens-2022'?'Las prioridades ENS se concentran en retención homogénea de actividad, cláusulas de terceros y segregación de entornos.':'Las áreas prioritarias de mejora se sitúan en gestión de vulnerabilidades, trazabilidad de proveedores críticos y cierre de acciones dentro de plazo.'}</li><li>Se recomienda mantener un comité mensual de seguimiento con cuadro de mando ejecutivo y revisión formal de riesgos altos.</li><li>La calidad y coherencia de la evidencia documental es suficiente para una presentación profesional de auditoría demo.</li></ul></div></div><div class="report-grid" style="margin-top:16px"><div class="report-panel"><h3 style="margin-top:0">Distribución de incidentes, hallazgos y acciones</h3><svg class="report-svg" viewBox="0 0 520 240"><line x1="34" y1="190" x2="490" y2="190" stroke="#CBD5E1" stroke-width="2"/>${sevBars}</svg></div><div class="report-panel report-table"><h3 style="margin-top:0">Dominios evaluados</h3><div class="table-wrap"><table class="table"><thead><tr><th>Dominio</th><th>Cumple</th><th>Total</th><th>Cobertura</th></tr></thead><tbody>${summary.map(s=>`<tr><td>${s.name}</td><td>${s.ok}</td><td>${s.total}</td><td><b>${s.pct}%</b></td></tr>`).join('')}</tbody></table></div></div></div><h2>Riesgos prioritarios</h2><div class="table-wrap"><table class="table"><thead><tr><th>ID</th><th>Riesgo</th><th>Inherente</th><th>Residual</th><th>Tratamiento</th><th>Estado</th></tr></thead><tbody>${ris.sort((a,b)=>(b.likelihood*b.impact)-(a.likelihood*a.impact)).slice(0,6).map(r=>`<tr><td>${esc(r.id.toUpperCase())}</td><td><b>${esc(r.title)}</b><div class="muted">${esc(r.asset)}</div></td><td>${r.likelihood*r.impact}</td><td>${esc(r.residual||'-')}</td><td>${esc(r.treatment)}</td><td>${status(r.status)}</td></tr>`).join('')}</tbody></table></div><h2>Hallazgos</h2>${findingsTable(find)}<h2>Acciones en seguimiento</h2><div class="table-wrap"><table class="table"><thead><tr><th>Acción</th><th>Responsable</th><th>Fecha objetivo</th><th>Progreso</th><th>Estado</th></tr></thead><tbody>${acts.map(x=>`<tr><td><b>${esc(x.title)}</b><div class="muted">${esc(x.controlId||'Sin control')} · ${esc(x.priority||'Media')}</div></td><td>${esc(x.owner)}</td><td>${esc(x.due)}</td><td>${x.progress}%</td><td>${status(x.status)}</td></tr>`).join('')}</tbody></table></div><h2>Estado de controles</h2><div class="table-wrap"><table class="table"><thead><tr><th>Control</th><th>Título</th><th>Estado</th><th>Evidencias</th></tr></thead><tbody>${ctrls.map(c=>`<tr><td>${c.id}</td><td>${esc(c.title)}</td><td>${status(a.controlStates[c.id]||'pendiente')}</td><td>${docs.filter(d=>d.controlId===c.id).length}</td></tr>`).join('')}</tbody></table></div></div>`}function findingsTable(rows){return rows.length?`<table class="table"><thead><tr><th>Título</th><th>Control</th><th>Severidad</th><th>Estado</th></tr></thead><tbody>${rows.map(f=>`<tr><td>${esc(f.title)}</td><td>${f.controlId}</td><td>${f.severity}</td><td>${f.status}</td></tr>`).join('')}</tbody></table>`:'<p>No se han registrado hallazgos.</p>'}
function settings(){return `<div class="page-head"><div><h1>Configuración</h1><p class="muted">Preferencias generales de AuditHub.</p></div></div><div class="card"><div class="form-grid"><div class="field"><label>Organización</label><input id="setOrg" value="${esc(db.settings.organization)}"></div><div class="field"><label>Auditor</label><input id="setAuditor" value="${esc(db.settings.auditor)}"></div></div><div class="actions" style="margin-top:16px"><button class="btn primary" id="saveSettings">Guardar</button><button class="btn danger" id="resetData">Restablecer datos demo</button></div></div>`}
function searchItems(q){q=(q||'').trim().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');if(!q)return[];let hit=(v)=>String(v||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').includes(q),out=[];controls().forEach(c=>{if(hit(c.id)||hit(c.title)||hit(c.section))out.push({kind:'control',id:c.id,title:c.id+' · '+c.title,meta:c.section})});db.documents.filter(x=>x.auditId===state.auditId).forEach(x=>{if(hit(x.name)||hit(x.controlId)||hit(x.owner))out.push({kind:'doc',id:x.id,title:x.name,meta:'Documento · '+(x.controlId||'Sin control')})});db.risks.filter(x=>x.auditId===state.auditId).forEach(x=>{if(hit(x.title)||hit(x.asset)||hit(x.owner)||hit(x.description))out.push({kind:'risk',id:x.id,title:x.title,meta:'Riesgo · '+x.asset})});db.policies.filter(x=>x.auditId===state.auditId).forEach(x=>{if(hit(x.name)||hit(x.owner)||hit((x.controls||[]).join(' ')))out.push({kind:'policy',id:x.id,title:x.name,meta:'Política · '+x.status})});db.incidents.filter(x=>x.auditId===state.auditId).forEach(x=>{if(hit(x.title)||hit(x.description)||hit(x.owner)||hit(x.controlId))out.push({kind:'incident',id:x.id,title:x.title,meta:'Incidente · '+x.status})});db.suppliers.filter(x=>x.auditId===state.auditId).forEach(x=>{if(hit(x.name)||hit(x.service)||hit(x.category)||hit(x.owner))out.push({kind:'supplier',id:x.id,title:x.name,meta:'Proveedor · '+x.service})});db.findings.filter(x=>x.auditId===state.auditId).forEach(x=>{if(hit(x.title)||hit(x.description)||hit(x.controlId)||hit(x.owner))out.push({kind:'finding',id:x.id,title:x.title,meta:'Hallazgo · '+x.controlId})});db.actions.filter(x=>x.auditId===state.auditId).forEach(x=>{if(hit(x.title)||hit(x.description)||hit(x.owner)||hit(x.controlId))out.push({kind:'action',id:x.id,title:x.title,meta:'Acción · '+x.status})});return out.slice(0,30)}
function renderSearchResults(q){let host=$('.search');if(!host)return;host.querySelector('.search-results')?.remove();let items=searchItems(q);if(!q.trim())return;let box=document.createElement('div');box.className='search-results';box.innerHTML=items.length?items.slice(0,10).map(x=>`<button data-search-kind="${x.kind}" data-search-id="${x.id}"><b>${esc(x.title)}</b><span>${esc(x.meta)}</span></button>`).join(''):`<div class="search-empty">No se han encontrado resultados.</div>`;host.appendChild(box);bindSearchResultButtons(box)}
function bindSearchResultButtons(root=document){$$('[data-search-kind]',root).forEach(b=>b.onclick=()=>openSearchResult(b.dataset.searchKind,b.dataset.searchId))}
function openSearchResult(kind,id){state.query='';if(kind==='control'){state.controlId=id;state.view='audit';state.tab='resumen';render();return}if(kind==='doc'){state.modal='doc:'+id;render();setTimeout(()=>hydrateDocPreview(id),30);return}if(kind==='action'){state.modal='action:'+id;render();return}state.modal=kind+':'+id;render()}
function commentTimeline(items){return items?.length?`<div class="comment-timeline">${items.slice().reverse().map(c=>`<article><div class="comment-head"><b>${esc(c.author||c[1]||'Auditor')}</b><time>${esc(c.date||c[0]||'')}</time></div><p>${esc(c.text||c[2]||'')}</p></article>`).join('')}</div>`:'<div class="empty compact-empty">Todavía no hay comentarios de seguimiento.</div>'}
function relatedDocuments(x,kind){let ids=kind==='policy'?(x.controls||[]):[x.controlId].filter(Boolean);let docs=db.documents.filter(d=>d.auditId===state.auditId&&(ids.includes(d.controlId)||((x.documentIds||[]).includes(d.id))));return docs.length?`<div class="related-docs">${docs.map(d=>`<button class="related-doc" data-doc="${d.id}"><span class="file-icon">${esc(d.type)}</span><span><b>${esc(d.name)}</b><small>${esc(d.controlId)} · ${esc(d.status)}</small></span><em>Ver</em></button>`).join('')}</div>`:'<div class="empty compact-empty">No hay documentos relacionados.</div>'}
function entityDetail(kind,id){let x;if(kind==='risk'){x=db.risks.find(v=>v.id===id);if(!x)return null;let score=x.likelihood*x.impact,related=(x.documentIds||[]).map(id=>db.documents.find(d=>d.id===id)).filter(Boolean);return modalWrap('Detalle del riesgo',`<div class="detail-hero"><div><span class="eyebrow">${esc(x.id.toUpperCase())} · ${esc(x.controlId||'Sin control')}</span><h2>${esc(x.title)}</h2><p>${esc(x.description)}</p></div><span class="risk-level l${score>=15?'high':score>=8?'medium':'low'}">${score}/25</span></div><div class="detail-grid"><b>Activo / proceso</b><span>${esc(x.asset)}</span><b>Responsable</b><span>${esc(x.owner)}</span><b>Probabilidad</b><span>${x.likelihood}/5</span><b>Impacto</b><span>${x.impact}/5</span><b>Tratamiento</b><span>${esc(x.treatment)}</span><b>Riesgo residual</b><span>${esc(x.residual||'Pendiente')}/25</span><b>Control relacionado</b><span>${esc(x.controlId||'Sin asignar')}</span><b>Próxima revisión</b><span>${esc(x.reviewDate||'Pendiente')}</span><b>Estado</b><span>${status(x.status)}</span></div><section class="detail-section"><h3>Plan de tratamiento</h3><div class="risk-treatment-box"><p>${esc(x.treatmentPlan||'No definido')}</p><div class="viewer-note">${esc(x.evidenceSummary||'Datos de demostración.')}</div></div></section><section class="detail-section"><div class="section-title"><h3>Documentación y evidencias asociadas</h3><span class="muted">${related.length} documentos</span></div>${related.length?`<div class="risk-doc-grid">${related.map(d=>`<button class="risk-doc" data-doc="${d.id}"><span class="file-icon">${esc(d.type)}</span><span><b>${esc(d.name)}</b><small>${esc(d.controlId)} · ${esc(d.owner)} · ${esc(d.status)}</small></span></button>`).join('')}</div>`:'<div class="empty">No hay documentos asociados.</div>'}</section><section class="detail-section"><div class="section-title"><h3>Seguimiento y comentarios</h3><span class="muted">Registro cronológico</span></div>${commentTimeline(x.comments)}<div class="comment-form"><div class="field"><label>Fecha</label><input id="entityCommentDate" type="date" value="${new Date().toISOString().slice(0,10)}"></div><div class="field grow"><label>Nuevo comentario</label><textarea id="entityCommentText" placeholder="Decisión, avance, bloqueo o próxima actuación..."></textarea></div><button class="btn primary" data-save-entity-comment="risk:${x.id}">Añadir comentario</button></div></section><div class="detail-actions"><button class="btn primary" data-create-action-from="risk:${x.id}">Crear acción de tratamiento</button><button class="btn" data-close>Cerrar</button></div>`,null)}if(kind==='policy'){x=db.policies.find(v=>v.id===id);if(!x)return null;return modalWrap('Detalle de la política',`<div class="detail-hero"><div><span class="eyebrow">Versión ${esc(x.version)}</span><h2>${esc(x.name)}</h2><p>Documento gobernado dentro del ciclo de vida de políticas.</p></div>${status(x.status)}</div><div class="detail-grid"><b>Propietario</b><span>${esc(x.owner)}</span><b>Fecha de aprobación</b><span>${esc(x.approved||'Pendiente')}</span><b>Próxima revisión</b><span>${esc(x.review)}</span><b>Controles relacionados</b><span>${esc((x.controls||[]).join(', '))}</span></div><section class="detail-section"><div class="section-title"><h3>Documentos relacionados</h3><span class="muted">Política, procedimientos y evidencias asociadas</span></div>${relatedDocuments(x,'policy')}</section><div class="detail-actions"><button class="btn primary" data-policy-review="${x.id}">Registrar revisión</button><button class="btn" data-close>Cerrar</button></div>`,null)}if(kind==='incident'){x=db.incidents.find(v=>v.id===id);if(!x)return null;return modalWrap('Detalle del incidente',`<div class="detail-hero"><div><span class="eyebrow">${esc(x.date)} · ${esc(x.controlId)}</span><h2>${esc(x.title)}</h2><p>${esc(x.description)}</p></div>${status(x.severity)}</div><div class="detail-grid"><b>Responsable</b><span>${esc(x.owner)}</span><b>Estado</b><span>${status(x.status)}</span><b>Control relacionado</b><span>${esc(x.controlId)}</span><b>Fecha</b><span>${esc(x.date)}</span></div><section class="detail-section"><h3>Seguimiento operativo</h3><div class="checklist readonly"><label><input type="checkbox" checked disabled> Registro y clasificación</label><label><input type="checkbox" ${x.status==='Cerrado'?'checked':''} disabled> Contención y recuperación</label><label><input type="checkbox" ${x.status==='Cerrado'?'checked':''} disabled> Lecciones aprendidas</label></div></section><section class="detail-section"><div class="section-title"><h3>Bitácora del incidente</h3><span class="muted">Comentarios con fecha y autor</span></div>${commentTimeline(x.comments)}<div class="comment-form"><div class="field"><label>Fecha</label><input id="entityCommentDate" type="date" value="${new Date().toISOString().slice(0,10)}"></div><div class="field grow"><label>Nuevo registro</label><textarea id="entityCommentText" placeholder="Contención realizada, evidencia preservada, decisión o lección aprendida..."></textarea></div><button class="btn primary" data-save-entity-comment="incident:${x.id}">Añadir registro</button></div></section><section class="detail-section"><h3>Evidencias relacionadas</h3>${relatedDocuments(x,'incident')}</section><div class="detail-actions"><button class="btn primary" data-create-action-from="incident:${x.id}">Crear acción</button><button class="btn" data-close>Cerrar</button></div>`,null)}if(kind==='supplier'){x=db.suppliers.find(v=>v.id===id);if(!x)return null;return modalWrap('Detalle del proveedor',`<div class="detail-hero"><div><span class="eyebrow">${esc(x.category)}</span><h2>${esc(x.name)}</h2><p>${esc(x.service)}</p></div>${status(x.status)}</div><div class="detail-grid"><b>Criticidad</b><span>${status(x.criticality)}</span><b>Nivel de riesgo</b><span>${esc(x.risk)}/25</span><b>Responsable interno</b><span>${esc(x.owner)}</span><b>Próxima revisión</b><span>${esc(x.review)}</span></div><div class="progress" style="margin-top:16px"><span style="width:${Math.min(100,x.risk*4)}%"></span></div><section class="detail-section"><h3>Documentos y evidencias</h3>${relatedDocuments(x,'supplier')}</section><div class="detail-actions"><button class="btn primary" data-create-action-from="supplier:${x.id}">Crear acción de seguimiento</button><button class="btn" data-close>Cerrar</button></div>`,null)}if(kind==='finding'){x=db.findings.find(v=>v.id===id);if(!x)return null;let acts=db.actions.filter(a=>a.findingId===x.id);return modalWrap('Detalle del hallazgo',`<div class="detail-hero"><div><span class="eyebrow">${esc(x.controlId)}</span><h2>${esc(x.title)}</h2><p>${esc(x.description)}</p></div>${status(x.severity)}</div><div class="detail-grid"><b>Responsable</b><span>${esc(x.owner)}</span><b>Estado</b><span>${status(x.status)}</span><b>Fecha objetivo</b><span>${esc(x.due)}</span><b>Acciones asociadas</b><span>${acts.length}</span></div>${acts.length?`<div class="mini-list" style="margin-top:14px">${acts.map(a=>`<div class="mini-item"><div><b>${esc(a.title)}</b><div class="muted">${a.progress}% · ${esc(a.owner)}</div></div><button class="btn compact" data-action-detail="${a.id}">Continuar</button></div>`).join('')}</div>`:''}<section class="detail-section"><h3>Evidencias relacionadas</h3>${relatedDocuments(x,'finding')}</section><div class="detail-actions"><button class="btn primary" data-create-action-from="finding:${x.id}">Crear acción correctiva</button><button class="btn" data-close>Cerrar</button></div>`,null)}return null}
function modal(){let m=state.modal;if(/^(risk|policy|incident|supplier|finding):/.test(m||'')){let [kind,id]=m.split(':');return entityDetail(kind,id)||modalWrap('Elemento no encontrado','<p>No se ha encontrado el registro solicitado.</p>',null)}if(m==='riskMatrix')return modalWrap('Matriz de riesgos ampliada',`${riskMatrix(db.risks.filter(r=>r.auditId===state.auditId),true)}`,null);if(m==='search')return modalWrap('Resultados de búsqueda',`<div class="search-modal-list">${searchItems(state.query).map(x=>`<button data-search-kind="${x.kind}" data-search-id="${x.id}"><b>${esc(x.title)}</b><span>${esc(x.meta)}</span></button>`).join('')||'<div class="empty">No se han encontrado resultados.</div>'}</div>`,null);if(m==='newClient')return modalWrap('Nuevo cliente',`<div class="form-grid"><div class="field"><label>Código de cliente</label><input id="mClientCode" value="CLI-${String(db.clients.length+1).padStart(3,'0')}"></div><div class="field"><label>Nombre o razón social</label><input id="mClientName"></div><div class="field"><label>CIF demo</label><input id="mClientTax"></div><div class="field"><label>Sector</label><input id="mClientSector"></div><div class="field"><label>País</label><input id="mClientCountry" value="España"></div><div class="field"><label>Contacto</label><input id="mClientContact"></div><div class="field" style="grid-column:1/-1"><label>Correo</label><input id="mClientEmail"></div></div>`,'createClient');if(m==='newAudit')return modalWrap('Nueva auditoría',`<div class="form-grid"><div class="field"><label>Cliente</label><select id="mClient">${db.clients.map(c=>`<option value="${c.id}">${esc(c.code)} · ${esc(c.name)}</option>`).join('')}</select></div><div class="field"><label>Código de auditoría</label><input id="mAuditCode" value="${esc(client().code)}-ISO27001-2026-02"></div><div class="field"><label>Nombre</label><input id="mName" value="Auditoría ISO 27001"></div><div class="field"><label>Organización</label><input id="mOrg" value="${esc(client().name)}"></div><div class="field"><label>Marco</label><select id="mFw">${db.frameworks.map(f=>`<option value="${f.id}">${f.name}</option>`).join('')}</select></div><div class="field"><label>Categoría ENS (si aplica)</label><select id="mEnsCategory"><option>BÁSICA</option><option selected>MEDIA</option><option>ALTA</option></select></div><div class="field"><label>Responsable</label><input id="mLead" value="${esc(db.settings.auditor)}"></div><div class="field"><label>Fecha inicio</label><input id="mStart" type="date" value="2026-07-18"></div><div class="field"><label>Fecha fin</label><input id="mEnd" type="date" value="2026-10-31"></div><div class="field" style="grid-column:1/-1"><label>Alcance</label><textarea id="mScope"></textarea></div></div>`,'createAudit');
if(m==='newFinding')return modalWrap('Nuevo hallazgo',`<div class="form-grid"><div class="field" style="grid-column:1/-1"><label>Título</label><input id="mTitle"></div><div class="field"><label>Control</label><select id="mControl">${controls().map(c=>`<option ${c.id===state.controlId?'selected':''}>${c.id}</option>`).join('')}</select></div><div class="field"><label>Severidad</label><select id="mSeverity"><option>Baja</option><option selected>Media</option><option>Alta</option></select></div><div class="field"><label>Responsable</label><input id="mOwner"></div><div class="field"><label>Fecha objetivo</label><input id="mDue" type="date"></div><div class="field" style="grid-column:1/-1"><label>Descripción</label><textarea id="mDescription"></textarea></div></div>`,'createFinding');
if(m==='newAction')return modalWrap('Nueva acción',`<div class="form-grid"><div class="field" style="grid-column:1/-1"><label>Título</label><input id="mTitle"></div><div class="field"><label>Responsable</label><input id="mOwner"></div><div class="field"><label>Fecha objetivo</label><input id="mDue" type="date"></div></div>`,'createAction');
if(m==='newRisk')return modalWrap('Nuevo riesgo',`<div class="form-grid"><div class="field" style="grid-column:1/-1"><label>Riesgo</label><input id="mTitle"></div><div class="field"><label>Activo o proceso</label><input id="mAsset"></div><div class="field"><label>Responsable</label><input id="mOwner"></div><div class="field"><label>Probabilidad (1-5)</label><input id="mLikelihood" type="number" min="1" max="5" value="3"></div><div class="field"><label>Impacto (1-5)</label><input id="mImpact" type="number" min="1" max="5" value="3"></div><div class="field"><label>Tratamiento</label><select id="mTreatment"><option>Mitigar</option><option>Evitar</option><option>Transferir</option><option>Aceptar</option></select></div><div class="field"><label>Estado</label><select id="mStatus"><option>Identificado</option><option>En tratamiento</option><option>Aceptado</option><option>Cerrado</option></select></div><div class="field" style="grid-column:1/-1"><label>Descripción</label><textarea id="mDescription"></textarea></div></div>`,'createRisk');
if(m==='newPolicy')return modalWrap('Nueva política',`<div class="form-grid"><div class="field" style="grid-column:1/-1"><label>Nombre</label><input id="mName"></div><div class="field"><label>Propietario</label><input id="mOwner"></div><div class="field"><label>Versión</label><input id="mVersion" value="1.0"></div><div class="field"><label>Estado</label><select id="mStatus"><option>Borrador</option><option>En revisión</option><option>Aprobada</option></select></div><div class="field"><label>Fecha aprobación</label><input id="mApproved" type="date"></div><div class="field"><label>Próxima revisión</label><input id="mReview" type="date"></div><div class="field" style="grid-column:1/-1"><label>Controles relacionados (separados por coma)</label><input id="mControls" placeholder="A.5.1, A.5.36"></div></div>`,'createPolicy');
if(m==='newIncident')return modalWrap('Nuevo incidente',`<div class="form-grid"><div class="field" style="grid-column:1/-1"><label>Título</label><input id="mTitle"></div><div class="field"><label>Fecha</label><input id="mDate" type="date"></div><div class="field"><label>Severidad</label><select id="mSeverity"><option>Baja</option><option>Media</option><option>Alta</option><option>Crítica</option></select></div><div class="field"><label>Responsable</label><input id="mOwner"></div><div class="field"><label>Control relacionado</label><select id="mControl">${controls().map(c=>`<option>${c.id}</option>`).join('')}</select></div><div class="field"><label>Estado</label><select id="mStatus"><option>Abierto</option><option>Investigación</option><option>Contenido</option><option>Cerrado</option></select></div><div class="field" style="grid-column:1/-1"><label>Descripción</label><textarea id="mDescription"></textarea></div></div>`,'createIncident');
if(m==='newSupplier')return modalWrap('Nuevo proveedor',`<div class="form-grid"><div class="field"><label>Proveedor</label><input id="mName"></div><div class="field"><label>Categoría</label><input id="mCategory" placeholder="Cloud, SaaS, Consultoría..."></div><div class="field" style="grid-column:1/-1"><label>Servicio</label><input id="mService"></div><div class="field"><label>Criticidad</label><select id="mCriticality"><option>Baja</option><option>Media</option><option>Alta</option></select></div><div class="field"><label>Nivel de riesgo (1-25)</label><input id="mRisk" type="number" min="1" max="25" value="10"></div><div class="field"><label>Responsable</label><input id="mOwner"></div><div class="field"><label>Próxima revisión</label><input id="mReview" type="date"></div></div>`,'createSupplier');

if(m?.startsWith('doc:')){let d=db.documents.find(x=>x.id===m.slice(4));let source=d.previewPath||d.path||'';let hasPagePreview=Array.isArray(d.previewImages)&&d.previewImages.length>0;let isVisual=(d.type==='SVG'||d.type==='PNG'||d.type==='JPG'||d.type==='JPEG'||d.type==='WEBP'||/\.(svg|png|jpe?g|webp)$/i.test(d.path||''));let visualSource=d.previewImage||d.path||source;let preview=hasPagePreview?`<div class="evidence-preview document-pages">${d.previewImages.map((img,i)=>`<figure><img src="${img}" alt="Página ${i+1} de ${esc(d.name)}"><figcaption>Página ${i+1} de ${d.previewImages.length}</figcaption></figure>`).join('')}</div>`:isVisual?`<div class="evidence-preview image-preview"><img src="${visualSource}" alt="Vista previa de ${esc(d.name)}"></div>`:source?`<div class="evidence-preview"><iframe id="docPreviewFrame" src="${source}#toolbar=0&navpanes=0" title="Vista previa de ${esc(d.name)}"></iframe></div>`:`<div class="evidence-preview preview-loading" id="dynamicPreview">Preparando vista previa interna…</div>`;let previewMsg=hasPagePreview?`Vista previa visual del archivo original ${esc(d.type)}. No es un PDF descargable. El único botón de descarga entrega el archivo original.`:`Vista previa dentro de Auditoria365. Descargar es una acción independiente.`;let previewType=hasPagePreview?`${d.type} · Vista previa por páginas`:d.type;return modalWrap(d.name,`${preview}<div class="viewer-note">${previewMsg}</div><div class="meta-list"><b>Tipo</b><span>${previewType}</span><b>Control</b><span>${d.controlId}</span><b>Fecha</b><span>${d.added}</span><b>Estado</b><span>${status(d.status)}</span><b>Propietario</b><span>${esc(d.owner)}</span><b>Tamaño</b><span>${formatSize(d.size)}</span><b>Comentario</b><span>${esc(d.comment||'')}</span></div><div class="actions" style="margin-top:18px"><button class="btn" data-download="${d.id}">Descargar ${d.type} original</button><button class="btn danger" data-delete-doc="${d.id}">Eliminar</button></div>`,null)}

if(m?.startsWith('action:')){let a=db.actions.find(x=>x.id===m.slice(7));let comments=a.comments||[],checks=a.checklist||[];return modalWrap('Continuar acción',`<div class="action-detail-head"><div>${status(a.status)} <span class="badge">${esc(a.controlId||'')}</span></div><b>${a.progress}% completado</b></div><h2>${esc(a.title)}</h2><p class="muted">${esc(a.description||'')}</p><div class="form-grid"><div class="field"><label>Estado</label><select id="actionStatus">${['Pendiente','En curso','Bloqueada','En revisión','Completada'].map(x=>`<option ${x===a.status?'selected':''}>${x}</option>`).join('')}</select></div><div class="field"><label>Progreso</label><input id="actionProgress" type="range" min="0" max="100" value="${a.progress}" oninput="document.getElementById('progressValue').textContent=this.value+'%'"><b id="progressValue">${a.progress}%</b></div><div class="field"><label>Responsable</label><input id="actionOwner" value="${esc(a.owner)}"></div><div class="field"><label>Fecha objetivo</label><input id="actionDue" type="date" value="${esc(a.due)}"></div></div><h3>Subtareas</h3><div class="checklist">${checks.map((c,i)=>`<label><input type="checkbox" data-action-check="${i}" ${c[1]?'checked':''}><span>${esc(c[0])}</span></label>`).join('')}</div><h3>Registrar avance</h3><div class="field"><textarea id="actionComment" placeholder="Añade una actualización, decisión, bloqueo o referencia a una evidencia…"></textarea></div><div class="timeline compact">${comments.slice().reverse().map(c=>`<div class="timeline-item"><span></span><div><b>${esc(c[2])}</b><div class="muted">${esc(c[0])} · ${esc(c[1])}</div></div></div>`).join('')||'<div class="empty">Todavía no hay comentarios.</div>'}</div>`,null)}
return modalWrap('Función preparada',`<p>Esta primera versión deja la arquitectura lista para ampliar marcos y funcionalidades.</p>`,null)}
function modalWrap(title,body,action){return `<div class="modal-backdrop" data-close><div class="modal" onclick="event.stopPropagation()"><header><h3>${esc(title)}</h3><button class="btn" data-close>×</button></header><div class="body">${body}</div><footer><button class="btn" data-close>Cerrar</button>${action?`<button class="btn primary" id="${action}">Guardar</button>`:''}</footer></div></div>`}
function frameworks(){return `<div class="page-head"><div><h1>Marcos de trabajo</h1><p class="muted">Catálogo extensible de normas y marcos de auditoría.</p></div><button class="btn primary" data-open="newFramework">+ Añadir marco</button></div><div class="grid three compact-cards">${db.frameworks.map(f=>{let audits=db.audits.filter(a=>a.frameworkId===f.id),cats=[...new Set(audits.map(a=>a.ensCategory).filter(Boolean))];return `<div class="card framework-card"><div class="section-title"><span class="badge">Activo</span>${audits.length?`<span class="muted">${audits.length} auditoría${audits.length===1?'':'s'}</span>`:''}</div><h2>${esc(f.name)}</h2><p>${esc(f.description)}</p><div class="meta-list"><b>Secciones</b><span>${f.sections.length}</span><b>Controles</b><span>${f.sections.reduce((n,s)=>n+s.controls.length,0)}</span>${f.id==='ens-2022'?`<b>Categoría configurada</b><span>${cats.length?cats.map(c=>`<span class="ens-category ${slug(c)}">${esc(c)}</span>`).join(' '):'Sin auditoría ENS'}</span>`:''}</div></div>`}).join('')}<div class="card" style="border-style:dashed"><h3>Próximos marcos</h3><p class="muted">NIS2, DORA, ISO 42001 y marcos personalizados.</p></div></div>`}
const views={dashboard,clients,audits,frameworks,documents,risks,policies,incidents,suppliers,findings,actions:actionsView,reports,settings,audit:auditView,control:auditView};
function bind(){ $('#auditSwitcher')?.addEventListener('change',e=>{let a=db.audits.find(x=>x.id===e.target.value);if(a){state.auditId=a.id;state.clientId=a.clientId;let f=db.frameworks.find(x=>x.id===a.frameworkId);state.controlId=f?.sections?.[0]?.controls?.[0]?.[0]||'';state.tab='resumen';state.modal=null;render()}}); $$('[data-nav]').forEach(b=>b.onclick=()=>{state.view=b.dataset.nav;render()}); $$('[data-open-audit]').forEach(b=>b.onclick=()=>{state.auditId=b.dataset.openAudit;state.clientId=audit().clientId;state.controlId=fw()?.sections?.[0]?.controls?.[0]?.[0]||state.controlId;state.view='audit';render()}); $$('[data-control]').forEach(b=>b.onclick=()=>{state.controlId=b.dataset.control;state.tab='resumen';render()}); $$('[data-tab]').forEach(b=>b.onclick=()=>{state.tab=b.dataset.tab;render()}); $$('[data-open]').forEach(b=>b.onclick=()=>{state.modal=b.dataset.open;render()}); $$('[data-close]').forEach(b=>b.onclick=()=>{if(state.modal?.startsWith('doc:')&&state.modalParent){state.modal=state.modalParent;state.modalParent=null}else{state.modal=null;state.modalParent=null}render()}); $$('[data-upload]').forEach(b=>b.onclick=()=>{state.controlId=b.dataset.upload;$('#fileInput').click()}); $$('[data-doc]').forEach(b=>b.onclick=()=>{if(state.modal&&!state.modal.startsWith('doc:'))state.modalParent=state.modal;state.modal='doc:'+b.dataset.doc;render();setTimeout(()=>hydrateDocPreview(b.dataset.doc),30)});$$('[data-open-matrix]').forEach(b=>b.onclick=()=>{state.modalParent=null;state.modal='riskMatrix';render()}); $$('[data-action-detail]').forEach(b=>b.onclick=()=>{state.modal='action:'+b.dataset.actionDetail;render()});$$('[data-risk-detail]').forEach(b=>b.onclick=()=>{state.modalParent=null;state.modal='risk:'+b.dataset.riskDetail;render()});$$('[data-policy-detail]').forEach(b=>b.onclick=()=>{state.modalParent=null;state.modal='policy:'+b.dataset.policyDetail;render()});$$('[data-incident-detail]').forEach(b=>b.onclick=()=>{state.modalParent=null;state.modal='incident:'+b.dataset.incidentDetail;render()});$$('[data-supplier-detail]').forEach(b=>b.onclick=()=>{state.modalParent=null;state.modal='supplier:'+b.dataset.supplierDetail;render()});$$('[data-finding-detail]').forEach(b=>b.onclick=()=>{state.modalParent=null;state.modal='finding:'+b.dataset.findingDetail;render()});bindSearchResultButtons();$$('[data-create-action-from]').forEach(b=>b.onclick=()=>{let [kind,id]=b.dataset.createActionFrom.split(':');let src=(kind==='finding'?db.findings:kind==='risk'?db.risks:kind==='incident'?db.incidents:db.suppliers).find(x=>x.id===id);state.modal='newAction';render();setTimeout(()=>{let t=$('#mTitle');if(t&&src)t.value=(kind==='finding'?'Corregir: ':kind==='risk'?'Tratar riesgo: ':kind==='incident'?'Seguimiento incidente: ':'Seguimiento proveedor: ')+((src.title||src.name));let o=$('#mOwner');if(o&&src?.owner)o.value=src.owner},0)});$$('[data-policy-review]').forEach(b=>b.onclick=()=>{let p=db.policies.find(x=>x.id===b.dataset.policyReview);if(p){p.status='En revisión';p.review=new Date(Date.now()+31536000000).toISOString().slice(0,10);save();toast('Revisión de política registrada');state.modal=null;render()}});$$('[data-save-entity-comment]').forEach(b=>b.onclick=()=>{let [kind,id]=b.dataset.saveEntityComment.split(':');let list=kind==='risk'?db.risks:db.incidents;let item=list.find(x=>x.id===id);let text=$('#entityCommentText')?.value.trim();let date=$('#entityCommentDate')?.value;if(!item||!text){toast('Escribe un comentario');return}item.comments||(item.comments=[]);item.comments.push({date:date||new Date().toISOString().slice(0,10),author:db.settings.auditor,text});db.history.push({auditId:item.auditId,controlId:item.controlId||'',date:new Date().toLocaleString('es-ES'),user:db.settings.auditor,action:(kind==='risk'?'Comentario de riesgo: ':'Registro de incidente: ')+(item.title||''),state:item.status});save();toast('Seguimiento registrado');render()}); $('#menuBtn')?.addEventListener('click',()=>$('#sidebar').classList.toggle('open')); let gs=$('#globalSearch');gs?.addEventListener('input',e=>{state.query=e.target.value;renderSearchResults(state.query)});gs?.addEventListener('keydown',e=>{if(e.key==='Enter'){state.query=e.target.value;state.modal='search';render()}});gs?.addEventListener('focus',()=>renderSearchResults(state.query));document.addEventListener('click',e=>{if(!e.target.closest('.search'))$('.search-results')?.remove()},{once:true}); $('#saveValidation')?.addEventListener('click',()=>{audit().controlStates[state.controlId]=$('#controlState').value;audit().notes[state.controlId]=$('#controlNotes').value;db.history.push({auditId:state.auditId,controlId:state.controlId,date:new Date().toLocaleString('es-ES'),user:db.settings.auditor,action:'Evaluación actualizada',state:$('#controlState').value});save();toast('Evaluación guardada');render()}); $('#saveSettings')?.addEventListener('click',()=>{db.settings.organization=$('#setOrg').value;db.settings.auditor=$('#setAuditor').value;save();toast('Configuración guardada');render()}); $('#resetData')?.addEventListener('click',()=>{if(confirm('¿Restablecer todos los datos?')){db=clone(window.AUDITHUB_SEED);save();render()}}); $('#createAudit')?.addEventListener('click',createAudit);$('#createClient')?.addEventListener('click',createClient);$('#createFinding')?.addEventListener('click',createFinding);$('#createAction')?.addEventListener('click',createAction);$('#createRisk')?.addEventListener('click',createRisk);$('#createPolicy')?.addEventListener('click',createPolicy);$('#createIncident')?.addEventListener('click',createIncident);$('#createSupplier')?.addEventListener('click',createSupplier);$$('[data-delete-doc]').forEach(b=>b.onclick=async()=>{db.documents=db.documents.filter(d=>d.id!==b.dataset.deleteDoc);await idbDelete(b.dataset.deleteDoc);save();if(state.modalParent){state.modal=state.modalParent;state.modalParent=null}else state.modal=null;render()});$$('[data-download]').forEach(b=>b.onclick=()=>downloadBlob(b.dataset.download)); $('#saveActionProgress')?.addEventListener('click',saveActionProgress); if(state.modal?.startsWith('action:')){let foot=$('.modal footer');if(foot&&!$('#saveActionProgress'))foot.insertAdjacentHTML('beforeend','<button class="btn primary" id="saveActionProgress">Guardar avance</button>');$('#saveActionProgress')?.addEventListener('click',saveActionProgress)} }
$('#fileInput').addEventListener('change',async e=>{for(const file of e.target.files){let id='d'+Date.now()+Math.random().toString(16).slice(2);let ext=(file.name.split('.').pop()||'FILE').toUpperCase(),cat=['SVG','PNG','JPG','JPEG','WEBP'].includes(ext)?'diagramas':ext==='XLSX'?'hojas-calculo':['DOCX','PDF'].includes(ext)?'documentacion':'evidencias',base=`evidencias/${client().code}/${audit().code}/${audit().frameworkCode||fw().short}/${state.controlId}/${cat}`;let doc={id,clientId:client().id,auditId:state.auditId,auditCode:audit().code,controlId:state.controlId,name:file.name,type:ext,size:file.size,added:new Date().toISOString().slice(0,10),owner:db.settings.auditor,status:'En revisión',comment:'',folderPath:base};db.documents.push(doc);await idbPut(id,file)}save();e.target.value='';toast('Documentos añadidos');render()});
function createClient(){let code=$('#mClientCode').value.trim(),name=$('#mClientName').value.trim();if(!code||!name){toast('Código y nombre son obligatorios');return}db.clients.push({id:'cli-'+Date.now(),code,name,taxId:$('#mClientTax').value,sector:$('#mClientSector').value,country:$('#mClientCountry').value,contact:$('#mClientContact').value,email:$('#mClientEmail').value,status:'Activo'});state.modal=null;save();state.view='clients';render()}
function createAudit(){let id='audit-'+Date.now(),clientId=$('#mClient').value,c=db.clients.find(x=>x.id===clientId),frameworkId=$('#mFw').value,f=db.frameworks.find(x=>x.id===frameworkId),code=$('#mAuditCode').value.trim();db.audits.push({id,code,clientId,name:$('#mName').value,organization:$('#mOrg').value||c?.name,frameworkId,frameworkCode:(f?.short||frameworkId).replace(/\s+/g,'-'),lead:$('#mLead').value,start:$('#mStart').value,end:$('#mEnd').value,status:'En progreso',scope:$('#mScope').value,ensCategory:frameworkId==='ens-2022'?$('#mEnsCategory').value:'',ensDimensions:frameworkId==='ens-2022'?{Disponibilidad:'MEDIO',Autenticidad:'MEDIO',Integridad:'MEDIO',Confidencialidad:'MEDIO',Trazabilidad:'MEDIO'}:{},controlStates:{},notes:{}});state.auditId=id;state.clientId=clientId;state.controlId=f?.sections?.[0]?.controls?.[0]?.[0]||'';state.modal=null;save();state.view='audit';render()}
function createFinding(){db.findings.push({id:'f'+Date.now(),auditId:state.auditId,controlId:$('#mControl').value,title:$('#mTitle').value,severity:$('#mSeverity').value,status:'Abierto',owner:$('#mOwner').value,due:$('#mDue').value,description:$('#mDescription').value});state.modal=null;save();render()}
function createAction(){db.actions.push({id:'a'+Date.now(),auditId:state.auditId,title:$('#mTitle').value,owner:$('#mOwner').value,due:$('#mDue').value,status:'Pendiente',progress:0});state.modal=null;save();render()}
function createRisk(){db.risks.push({id:'r'+Date.now(),auditId:state.auditId,title:$('#mTitle').value,asset:$('#mAsset').value,owner:$('#mOwner').value,likelihood:+$('#mLikelihood').value,impact:+$('#mImpact').value,treatment:$('#mTreatment').value,status:$('#mStatus').value,description:$('#mDescription').value});state.modal=null;save();render()}
function createPolicy(){db.policies.push({id:'p'+Date.now(),auditId:state.auditId,name:$('#mName').value,owner:$('#mOwner').value,version:$('#mVersion').value,status:$('#mStatus').value,approved:$('#mApproved').value,review:$('#mReview').value,controls:$('#mControls').value.split(',').map(x=>x.trim()).filter(Boolean)});state.modal=null;save();render()}
function createIncident(){db.incidents.push({id:'i'+Date.now(),auditId:state.auditId,title:$('#mTitle').value,date:$('#mDate').value,severity:$('#mSeverity').value,owner:$('#mOwner').value,controlId:$('#mControl').value,status:$('#mStatus').value,description:$('#mDescription').value});state.modal=null;save();render()}
function createSupplier(){db.suppliers.push({id:'s'+Date.now(),auditId:state.auditId,name:$('#mName').value,category:$('#mCategory').value,service:$('#mService').value,criticality:$('#mCriticality').value,risk:+$('#mRisk').value,owner:$('#mOwner').value,review:$('#mReview').value,status:'Evaluado'});state.modal=null;save();render()}
function formatSize(n){if(!n)return '0 KB';return n>1048576?(n/1048576).toFixed(1)+' MB':Math.max(1,Math.round(n/1024))+' KB'}
async function hydrateDocPreview(id){let d=db.documents.find(x=>x.id===id);if(!d||d.path||d.previewPath)return;let box=$('#dynamicPreview');if(!box)return;let base=await idb();let req=base.transaction('files').objectStore('files').get(id);req.onsuccess=()=>{let f=req.result;if(!f){box.textContent='No se ha encontrado el archivo.';return}let url=URL.createObjectURL(f);if(f.type.startsWith('image/'))box.innerHTML=`<img src="${url}" alt="Vista previa">`;else if(f.type==='application/pdf')box.innerHTML=`<iframe src="${url}#toolbar=0" title="Vista previa"></iframe>`;else if(f.type.startsWith('text/')||/\.(txt|csv)$/i.test(d.name)){let r=new FileReader();r.onload=()=>box.innerHTML=`<pre class="text-preview">${esc(r.result)}</pre>`;r.readAsText(f)}else box.innerHTML='<div class="office-placeholder"><b>Vista previa no disponible para este archivo local</b><p>DOCX y XLSX añadidos por el usuario necesitan un conversor en navegador. El documento no se descarga automáticamente y permanece almacenado localmente.</p></div>'}}
function saveActionProgress(){let id=state.modal?.slice(7),a=db.actions.find(x=>x.id===id);if(!a)return;a.status=$('#actionStatus').value;a.progress=Number($('#actionProgress').value);a.owner=$('#actionOwner').value;a.due=$('#actionDue').value;$$('[data-action-check]').forEach(x=>{a.checklist[Number(x.dataset.actionCheck)][1]=x.checked});let comment=$('#actionComment').value.trim();if(comment){a.comments||(a.comments=[]);a.comments.push([new Date().toLocaleDateString('es-ES'),db.settings.auditor,comment])}db.history.push({auditId:a.auditId,controlId:a.controlId,date:new Date().toLocaleString('es-ES'),user:db.settings.auditor,action:'Acción actualizada: '+a.title,state:a.status});save();toast('Avance de la acción guardado');state.modal=null;render()}
function toast(msg){let t=document.createElement('div');t.className='toast';t.textContent=msg;document.body.appendChild(t);setTimeout(()=>t.remove(),1800)}
function idb(){return new Promise((res,rej)=>{let r=indexedDB.open('audithub-files',1);r.onupgradeneeded=()=>r.result.createObjectStore('files');r.onsuccess=()=>res(r.result);r.onerror=()=>rej(r.error)})}
async function idbPut(id,file){let d=await idb();return new Promise((res,rej)=>{let t=d.transaction('files','readwrite');t.objectStore('files').put(file,id);t.oncomplete=res;t.onerror=()=>rej(t.error)})}
async function idbDelete(id){let d=await idb();return new Promise(res=>{let t=d.transaction('files','readwrite');t.objectStore('files').delete(id);t.oncomplete=res})}
async function downloadBlob(id){let doc=db.documents.find(x=>x.id===id);let d=await idb();let t=d.transaction('files');let r=t.objectStore('files').get(id);r.onsuccess=()=>{let a=document.createElement('a');if(r.result){a.href=URL.createObjectURL(r.result);a.download=doc?.name||'archivo';a.click();setTimeout(()=>URL.revokeObjectURL(a.href),1000)}else if(doc?.path){a.href=doc.path;a.download=doc.name;a.click()}else toast('No se ha encontrado el archivo')}}
render();
})();
